/*
-- Classes
1.230      mxContract|CONTRACT
1.685      mxContract|PACKAGE_SINGLE
1.238      mxContract|SINGLE
1.239      mxContract|TRADE
MCbSQ03911 mxContract|PACKAGE
MTpFC44943 mxSystemClassification|FOLDER

-- Find value of relevant JOIN
select * from CSF_JOIN_DBF where rtrim(M_LABEL) = 'ContractClassifJoin'

-- Find value of relevant NODE_REF
select * from CSF_FOLDER_DBF

-- Trade identifiers, TRN.CNT.PCK
select
trn.M_NB       TRN, 
trn.M_CONTRACT CNT,
cnt.M_PACK_REF PCK
from TRN_HDR_DBF trn
left join CONTRACT_DBF cnt on trn.M_CONTRACT = cnt.M_REFERENCE
left join PACKAGE_DBF  pck on cnt.M_PACK_REF = pck.M_REFERENCE

where M_NB in (, ' ');
*/



